<h1 data-start="136" data-end="176">💻 ✅ COMPLETE MYSQL PROJECT (ONE FILE)</h1>
<pre class="overflow-visible! px-0!" data-start="178" data-end="2673"><div class="relative w-full mt-4 mb-1"><div class=""><div class="relative"><div class="h-full min-h-0 min-w-0"><div class="h-full min-h-0 min-w-0" style="width: 100%; transform: none;"><div class="border border-token-border-light border-radius-3xl corner-superellipse/1.1 rounded-3xl"><div class="h-full w-full border-radius-3xl bg-token-bg-elevated-secondary corner-superellipse/1.1 overflow-clip rounded-3xl lxnfua_clipPathFallback"><div class="sticky z-2 select-none top-(--sticky-padding-top)"><div class="flex w-full items-center justify-between py-1.5 ps-4 pe-1.5 font-sans md:ps-5 bg-token-bg-elevated-secondary"><div class="flex max-w-[75%] min-w-0 cursor-default items-center text-sm font-medium justify-self-start text-token-text-primary"><svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" aria-hidden="true" class="icon-sm me-2.5 shrink-0"><use href="/cdn/assets/sprites-core-97566a9e.svg#e45ab3" fill="currentColor"></use></svg>SQL</div><div class="flex flex-row items-center gap-0.5 justify-self-end"><button class="flex gap-1 items-center select-none py-2 text-sm font-medium hover:bg-black/5 dark:hover:bg-white/10 size-9 rounded-full px-2" aria-label="Copy" data-state="closed"><svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" aria-hidden="true" class="icon-md"><use href="/cdn/assets/sprites-core-97566a9e.svg#ce3544" fill="currentColor"></use></svg></button></div></div></div><div class="pointer-events-none absolute inset-x-4 top-12 bottom-4"><div class="pointer-events-none sticky z-40 shrink-0 z-1!" style="top: calc(calc(var(--sticky-padding-top) + 48px) - 1px * 3); margin-bottom: calc(-4px); height: calc(4px); mask-image: linear-gradient(transparent 25%, white 75%);"><div class="sticky bg-token-border-light" style="top: calc(var(--sticky-padding-top) + 48px); height: 1px;"></div></div></div><div class="relative"><div class="" style="transform: none;"><div class="relative z-0 flex max-w-full"><div id="code-block-viewer" dir="ltr" class="q9tKkq_viewer cm-editor z-10 light:cm-light dark:cm-light flex h-full w-full flex-col items-stretch ͼ5 ͼj"><div class="cm-scroller"><div class="cm-content q9tKkq_readonly"><span class="ͼ6">-- =========================================</span><br><span class="ͼ6">-- EMPLOYEE MANAGEMENT SYSTEM PROJECT</span><br><span class="ͼ6">-- =========================================</span><br><br><span class="ͼ6">-- 1. Create Database</span><br><span class="ͼ8">CREATE</span><span> DATABASE employee_db;</span><br><span>USE employee_db;</span><br><br><span class="ͼ6">-- =========================================</span><br><span class="ͼ6">-- 2. Create Tables</span><br><span class="ͼ6">-- =========================================</span><br><br><span class="ͼ6">-- Department Table (One-to-Many)</span><br><span class="ͼ8">CREATE</span><span> </span><span class="ͼ8">TABLE</span><span> departments (</span><br><span>    dept_id </span><span class="ͼe">INT</span><span> </span><span class="ͼ8">PRIMARY</span><span> </span><span class="ͼ8">KEY</span><span> AUTO_INCREMENT,</span><br><span>    dept_name </span><span class="ͼe">VARCHAR</span><span>(</span><span class="ͼb">50</span><span>)</span><br><span>);</span><br><br><span class="ͼ6">-- Employees Table (Many-to-One)</span><br><span class="ͼ8">CREATE</span><span> </span><span class="ͼ8">TABLE</span><span> employees (</span><br><span>    emp_id </span><span class="ͼe">INT</span><span> </span><span class="ͼ8">PRIMARY</span><span> </span><span class="ͼ8">KEY</span><span> AUTO_INCREMENT,</span><br><span>    emp_name </span><span class="ͼe">VARCHAR</span><span>(</span><span class="ͼb">50</span><span>),</span><br><span>    dept_id </span><span class="ͼe">INT</span><span>,</span><br><span>    </span><span class="ͼ8">FOREIGN</span><span> </span><span class="ͼ8">KEY</span><span> (dept_id) </span><span class="ͼ8">REFERENCES</span><span> departments(dept_id)</span><br><span>);</span><br><br><span class="ͼ6">-- Salary Table (One-to-One)</span><br><span class="ͼ8">CREATE</span><span> </span><span class="ͼ8">TABLE</span><span> salaries (</span><br><span>    salary_id </span><span class="ͼe">INT</span><span> </span><span class="ͼ8">PRIMARY</span><span> </span><span class="ͼ8">KEY</span><span> AUTO_INCREMENT,</span><br><span>    emp_id </span><span class="ͼe">INT</span><span> </span><span class="ͼ8">UNIQUE</span><span>,</span><br><span>    salary </span><span class="ͼe">DECIMAL</span><span>(</span><span class="ͼb">10</span><span>,</span><span class="ͼb">2</span><span>),</span><br><span>    </span><span class="ͼ8">FOREIGN</span><span> </span><span class="ͼ8">KEY</span><span> (emp_id) </span><span class="ͼ8">REFERENCES</span><span> employees(emp_id)</span><br><span>);</span><br><br><span class="ͼ6">-- Projects Table</span><br><span class="ͼ8">CREATE</span><span> </span><span class="ͼ8">TABLE</span><span> projects (</span><br><span>    project_id </span><span class="ͼe">INT</span><span> </span><span class="ͼ8">PRIMARY</span><span> </span><span class="ͼ8">KEY</span><span> AUTO_INCREMENT,</span><br><span>    emp_id </span><span class="ͼe">INT</span><span>,</span><br><span>    project_name </span><span class="ͼe">VARCHAR</span><span>(</span><span class="ͼb">100</span><span>),</span><br><span>    </span><span class="ͼ8">FOREIGN</span><span> </span><span class="ͼ8">KEY</span><span> (emp_id) </span><span class="ͼ8">REFERENCES</span><span> employees(emp_id)</span><br><span>);</span><br><br><span class="ͼ6">-- =========================================</span><br><span class="ͼ6">-- 3. Insert Data</span><br><span class="ͼ6">-- =========================================</span><br><br><span class="ͼ6">-- Departments</span><br><span class="ͼ8">INSERT</span><span> </span><span class="ͼ8">INTO</span><span> departments (dept_name) </span><span class="ͼ8">VALUES</span><br><span>(</span><span class="ͼc">'HR'</span><span>),</span><br><span>(</span><span class="ͼc">'IT'</span><span>),</span><br><span>(</span><span class="ͼc">'Sales'</span><span>);</span><br><br><span class="ͼ6">-- Employees</span><br><span class="ͼ8">INSERT</span><span> </span><span class="ͼ8">INTO</span><span> employees (emp_name, dept_id) </span><span class="ͼ8">VALUES</span><br><span>(</span><span class="ͼc">'Manoj'</span><span>, </span><span class="ͼb">2</span><span>),</span><br><span>(</span><span class="ͼc">'Diya'</span><span>, </span><span class="ͼb">1</span><span>),</span><br><span>(</span><span class="ͼc">'Harry'</span><span>, </span><span class="ͼb">2</span><span>),</span><br><span>(</span><span class="ͼc">'Kushal'</span><span>, </span><span class="ͼb">3</span><span>);</span><br><br><span class="ͼ6">-- Salaries (One-to-One)</span><br><span class="ͼ8">INSERT</span><span> </span><span class="ͼ8">INTO</span><span> salaries (emp_id, salary) </span><span class="ͼ8">VALUES</span><br><span>(</span><span class="ͼb">1</span><span>, </span><span class="ͼb">50000</span><span>),</span><br><span>(</span><span class="ͼb">2</span><span>, </span><span class="ͼb">40000</span><span>),</span><br><span>(</span><span class="ͼb">3</span><span>, </span><span class="ͼb">55000</span><span>),</span><br><span>(</span><span class="ͼb">4</span><span>, </span><span class="ͼb">45000</span><span>);</span><br><br><span class="ͼ6">-- Projects</span><br><span class="ͼ8">INSERT</span><span> </span><span class="ͼ8">INTO</span><span> projects (emp_id, project_name) </span><span class="ͼ8">VALUES</span><br><span>(</span><span class="ͼb">1</span><span>, </span><span class="ͼc">'Website Development'</span><span>),</span><br><span>(</span><span class="ͼb">1</span><span>, </span><span class="ͼc">'Mobile App'</span><span>),</span><br><span>(</span><span class="ͼb">2</span><span>, </span><span class="ͼc">'Recruitment System'</span><span>),</span><br><span>(</span><span class="ͼb">3</span><span>, </span><span class="ͼc">'Admin Dashboard'</span><span>),</span><br><span>(</span><span class="ͼb">4</span><span>, </span><span class="ͼc">'Marketing Campaign'</span><span>);</span><br><br><span class="ͼ6">-- =========================================</span><br><span class="ͼ6">-- 4. JOIN QUERIES</span><br><span class="ͼ6">-- =========================================</span><br><br><span class="ͼ6">-- INNER JOIN (Employee + Department)</span><br><span class="ͼ8">SELECT</span><span> e.emp_name, d.dept_name</span><br><span class="ͼ8">FROM</span><span> employees e</span><br><span class="ͼ8">INNER</span><span> </span><span class="ͼ8">JOIN</span><span> departments d</span><br><span class="ͼ8">ON</span><span> e.dept_id </span><span class="ͼ8">=</span><span> d.dept_id;</span><br><br><span class="ͼ6">-- LEFT JOIN (All Employees + Projects)</span><br><span class="ͼ8">SELECT</span><span> e.emp_name, p.project_name</span><br><span class="ͼ8">FROM</span><span> employees e</span><br><span class="ͼ8">LEFT</span><span> </span><span class="ͼ8">JOIN</span><span> projects p</span><br><span class="ͼ8">ON</span><span> e.emp_id </span><span class="ͼ8">=</span><span> p.emp_id;</span><br><br><span class="ͼ6">-- RIGHT JOIN (All Projects)</span><br><span class="ͼ8">SELECT</span><span> p.project_name, e.emp_name</span><br><span class="ͼ8">FROM</span><span> employees e</span><br><span class="ͼ8">RIGHT</span><span> </span><span class="ͼ8">JOIN</span><span> projects p</span><br><span class="ͼ8">ON</span><span> e.emp_id </span><span class="ͼ8">=</span><span> p.emp_id;</span><br><br><span class="ͼ6">-- MULTIPLE JOIN (Employee + Department + Salary)</span><br><span class="ͼ8">SELECT</span><span> e.emp_name, d.dept_name, s.salary</span><br><span class="ͼ8">FROM</span><span> employees e</span><br><span class="ͼ8">JOIN</span><span> departments d </span><span class="ͼ8">ON</span><span> e.dept_id </span><span class="ͼ8">=</span><span> d.dept_id</span><br><span class="ͼ8">JOIN</span><span> salaries s </span><span class="ͼ8">ON</span><span> e.emp_id </span><span class="ͼ8">=</span><span> s.emp_id;</span><br><br><span class="ͼ6">-- =========================================</span><br><span class="ͼ6">-- END OF PROJECT</span><br><span class="ͼ6">-- =========================================</span></div></div></div></div></div></div></div></div></div></div><div class=""><div class="" style="width: 100%; transform: none;"></div></div></div></div></div></pre>
