GN</span><span> </span><span class="ͼ8">KEY</span><span> (emp_id) </span><span class="ͼ8">REFERENCES</span><span> employees(emp_id)</span><br><span>);</span><br><br><span class="ͼ8">CREATE</span><span> </span><span class="ͼ8">TABLE</span><span> projects (</span><br><span>    project_id </span><span class="ͼe">INT</span><span> </span><span class="ͼ8">PRIMARY</span><span> </span><span class="ͼ8">KEY</span><span> AUTO_INCREMENT,</span><br><span>    emp_id </span><span class="ͼe">INT</span><span>,</span><br><span>    project_name </span><span class="ͼe">VARCHAR</span><span>(</span><span class="ͼb">100</span><span>),</span><br><span>    </span><span class="ͼ8">FOREIGN</span><span> </span><span class="ͼ8">KEY</span><span> (emp_id) </span><span class="ͼ8">REFERENCES</span><span> employees(emp_id)</span><br><span>);</span><br><br><span class="ͼ8">INSERT</span><span> </span><span class="ͼ8">INTO</span><span> departments (dept_name) </span><span class="ͼ8">VALUES</span><br><span>(</span><span class="ͼc">'HR'</span><span>),</span><br><span>(</span><span class="ͼc">'IT'</span><span>),</span><br><span>(</span><span class="ͼc">'Sales'</span><span>);</span><br><br><span class="ͼ8">INSERT</span><span> </span><span class="ͼ8">INTO</span><span> employees (emp_name, dept_id) </span><span class="ͼ8">VALUES</span><br><span>(</span><span class="ͼc">'Manoj'</span><span>, </span><span class="ͼb">2</span><span>),</span><br><span>(</span><span class="ͼc">'Diya'</span><span>, </span><span class="ͼb">1</span><span>),</span><br><span>(</span><span class="ͼc">'Harry'</span><span>, </span><span class="ͼb">2</span><span>),</span><br><span>(</span><span class="ͼc">'Kushal'</span><span>, </span><span class="ͼb">3</span><span>);</span><br><br><span class="ͼ8">INSERT</span><span> </span><span class="ͼ8">INTO</span><span> salaries (emp_id, salary) </span><span class="ͼ8">VALUES</span><br><span>(</span><span class="ͼb">1</span><span>, </span><span class="ͼb">50000</span><span>),</span><br><span>(</span>